public boolean xyBalance(String str) {
    boolean isBalanced = true;
    int lastIndexX = str.lastIndexOf('x');
    int lastIndexY = str.lastIndexOf('y');

    if (lastIndexX > lastIndexY) {
        isBalanced = false;
    }

    return isBalanced;
}
